@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication

<nav class="step-indicator" aria-label="Application progress">
    <ol>
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var status = step < CurrentStep ? "completed"
                       : step == CurrentStep ? "active"
                       : "upcoming";
            <li class="step @status"
                role="button"
                tabindex="@(status == "completed" ? 0 : -1)"
                @onclick="() => OnStepClick(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span class="checkmark" aria-hidden="true">✓</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
