    padding: 0;
    margin: 0 0 2rem 0;
    counter-reset: step;
}

.step {
    flex: 1;
    text-align: center;
    position: relative;
    cursor: default;
}

.step.completed {
    cursor: pointer;
}

.step + .step::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed + .step::before,
.step.active + .step::before {
    background: #dee2e6;
}

.step.completed + .step.completed::before,
.step.completed + .step.active::before {
    background: #0d6efd;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
    transition: background-color 0.2s, color 0.2s;
}

.step.completed .step-circle {
    background: #0d6efd;
    color: #fff;
}

.step.active .step-circle {
    background: #0d6efd;
    color: #fff;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

.step.upcoming .step-circle {
    background: #dee2e6;
    color: #6c757d;
}

.step-label {
    display: block;
    margin-top: 0.5rem;
    font-size: 0.8rem;
    font-weight: 500;
}

.step.completed .step-label {
    color: #0d6efd;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 700;
}

.step.upcoming .step-label {
    color: #adb5bd;
}

.checkmark {
    font-size: 1rem;
}

