arguments.file_text:
@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (IsValidatingEmail)
        {
            <span class="hint">Validating email…</span>
        }
    </div>

    <div class="form-group">
        <label>Phone <span class="required">*</span></label>
        <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 555-5555" />
    </div>

    <div class="form-group">
        <label>Address <span class="required">*</span></label>
        <textarea @bind="Model.Address" @bind:event="oninput" rows="2" placeholder="123 Main St, City, State"></textarea>
    </div>

    <div class="step-buttons">
        <span></span>
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">
            @(IsValidatingEmail ? "Validating…" : "Next →")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidatingEmail;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidatingEmail = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            IsValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>Work History</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
            if (entry.StartDate is null)
            {
                ErrorMessage = "Each position must have a start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>References</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ErrorMessage = "Each reference must have a name and email.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication

<section>
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea @bind="CoverLetter" @bind:event="oninput" @bind:after="NotifyChanged"
                  rows="12" maxlength="@MaxLength"
                  placeholder="Tell us why you're a great fit for this role..."></textarea>
        <span class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </span>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? ErrorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

.char-count {
    display: block;
    text-align: right;
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

.char-count.over-limit {
    color: #dc3545;
    font-weight: 600;
}

@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section class="review-step">
    <h2>Review & Submit</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @if (SubmittedId is not null)
    {
        <div class="confirmation" role="status">
            <h3>🎉 Application Submitted!</h3>
            <p>Your application ID is <strong>#@SubmittedId</strong>.</p>
            <p>We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button type="button" class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
