{"file_text": "@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section class="review-step">
    <h2>Review & Submit</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @if (SubmittedId is not null)
    {
        <div class="confirmation" role="status">
            <h3>🎉 Application Submitted!</h3>
            <p>Your application ID is <strong>#@SubmittedId</strong>.</p>
            <p>We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button type="button" class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <!-- Work History -->
        <div class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button type="button" class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <span class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <!-- References -->
        <div class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button type="button" class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-entry">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-muted">@r.Email · @r.Phone</span>
                </div>
            }
        </div>

        <!-- Cover Letter -->
        <div class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button type="button" class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(No cover letter provided)" : CoverLetter)</p>
        </div>

        <div class="step-buttons">
            <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
            <button type="button" class="btn-success" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting…" : "Submit Application")
            </button>
        </div>
    }
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEdit { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            SubmittedId = await OnSubmit();
        }
        catch
        {
            ErrorMessage = "Submission failed. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
