@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (IsValidatingEmail)
        {
            <span class="hint">Validating email…</span>
        }
    </div>

    <div class="form-group">
        <label>Phone <span class="required">*</span></label>
        <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 555-5555" />
    </div>

    <div class="form-group">
        <label>Address <span class="required">*</span></label>
        <textarea @bind="Model.Address" @bind:event="oninput" rows="2" placeholder="123 Main St, City, State"></textarea>
    </div>

    <div class="step-buttons">
        <span></span>
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">
            @(IsValidatingEmail ? "Validating…" : "Next →")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidatingEmail;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidatingEmail = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            IsValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}

