@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>Work History</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
            if (entry.StartDate is null)
            {
                ErrorMessage = "Each position must have a start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

