@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models

<section>
    <h2>References</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ErrorMessage = "Each reference must have a name and email.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

