@namespace sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication

<section>
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea @bind="CoverLetter" @bind:event="oninput" @bind:after="NotifyChanged"
                  rows="12" maxlength="@MaxLength"
                  placeholder="Tell us why you're a great fit for this role..."></textarea>
        <span class="char-count @(CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @CoverLetter.Length / @MaxLength characters
        </span>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</section>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? ErrorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

