arguments.file_text:
@page "/apply"
@rendermode InteractiveServer

@using sv_713b8eea2b89433daa44edb200346e2c.Components.JobApplication
@using sv_713b8eea2b89433daa44edb200346e2c.Models
@using sv_713b8eea2b89433daa44edb200346e2c.Services

@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep" OnNavigateToStep="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              ValidateEmail="AppService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnBack="PreviousStep"
                        OnEdit="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        return await AppService.SubmitApplicationAsync(application);
    }
}

.apply-page {
    max-width: 720px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.apply-page h1 {
    text-align: center;
    margin-bottom: 2rem;
    font-size: 1.75rem;
}

.apply-page h2 {
    font-size: 1.35rem;
    margin-bottom: 1.25rem;
    color: #212529;
}

/* Shared form styles */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    box-sizing: border-box;
    transition: border-color 0.15s;
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #0d6efd;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.required {
    color: #dc3545;
}

.hint {
    font-size: 0.8rem;
    color: #6c757d;
    font-style: italic;
}

.checkbox-label {
    display: inline-flex !important;
    align-items: center;
    gap: 0.4rem;
    font-weight: 400 !important;
    margin-top: 0.4rem;
    font-size: 0.85rem !important;
    cursor: pointer;
}

.checkbox-label input[type="checkbox"] {
    width: auto;
}

.validation-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
    border-radius: 6px;
    padding: 0.75rem 1rem;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

/* Step navigation buttons */
.step-buttons {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    padding-top: 1.25rem;
    border-top: 1px solid #dee2e6;
}

.btn-primary,
.btn-secondary,
.btn-outline,
